function solve(prices, strategy, k) {
    let maxProfit = 0;
    let n = prices.length;

    // Calculate the original profit
    let profit = 0;
    for (let i = 0; i < n; i++) {
        profit += strategy[i] * prices[i];
    }
    maxProfit = profit;

    // Try to find the best modification
    for (let i = 0; i <= n - k; i++) {
        // The modification is from i to i + k - 1
        // The first k/2 elements are set to 0 (hold)
        // The last k/2 elements are set to 1 (sell)
        // Calculate the change in profit
        let change = 0;
        for (let j = 0; j < k; j++) {
            if (j < k / 2) {
                // Original strategy was something, now it's 0
                // So we subtract the original contribution
                change -= strategy[i + j] * prices[i + j];
            } else {
                // Original strategy was something, now it's 1
                // So we add the new contribution
                change += prices[i + j];
            }
        }
        // Update maxProfit if this modification gives a better profit
        maxProfit = Math.max(maxProfit, profit + change);
    }

    return maxProfit;
}

